css:
@import url("https://fontsapi.zeoseven.com/488/main/result.css");

:root {
    --main-font: "STDongGuanTi";
    --main-weight: 900;
    --bg-color: rgba(20, 20, 20, 0.4);
    --bg-effect: blur(15px) saturate(180%);
    --border-style: 1px solid rgba(255, 255, 255, 0.1);
    --border-radius: 12px;
    --text-color: #C0C0C0;
    --menu-bg: rgba(25, 40, 65, 0.7);
    --menu-border: 1px solid rgba(80, 140, 255, 0.15);
    --menu-color: #E0F0FF;
    --message-bg: rgba(20, 20, 20, 0.5);
    --message-border: 1px solid rgba(255, 255, 255, 0.12);
    --message-radius: 16px;
}

/* 基础字体设置 */
body, 
.edit_textarea, 
textarea, 
input, 
pre, 
code, 
select, 
.text_pole, 
.inline-drawer-header, 
.neo-range-input, 
[class*="mdHotkeys"], 
#send_textarea,
#top-bar,
.mes_text {
    font-family: var(--main-font) !important;
    font-weight: var(--main-weight);
}

/* 通用UI元素样式 */
code,
select, 
.text_pole, 
.inline-drawer-header, 
.neo-range-input, 
[class*="mdHotkeys"], 
#send_textarea,
#top-bar {
    background: var(--bg-color) !important;
    backdrop-filter: var(--bg-effect);
    -webkit-backdrop-filter: var(--bg-effect);
    border: var(--border-style);
    border-radius: var(--border-radius);
    color: var(--text-color) !important;
}

/* 菜单按钮 */
.menu_button {
    font-family: var(--main-font), sans-serif !important;
    font-weight: var(--main-weight);
    background: var(--menu-bg);
    backdrop-filter: blur(12px) saturate(200%);
    -webkit-backdrop-filter: blur(12px) saturate(200%);
    border: var(--menu-border);
    border-radius: var(--border-radius);
    color: var(--menu-color);
    box-shadow: 0 2px 12px rgba(0, 20, 40, 0.25);
}

.menu_button.fa-solid,
.menu_button[class*="fa-"] {
    font-family: "Font Awesome 6 Free", "Font Awesome 5 Free" !important;
}

/* 消息区域 */
.mes_block {
    padding: 10px 0px 10px 10px;
    padding-top: 20px;
    padding-bottom: 40px;
    width: 106%;
    background: var(--message-bg) !important;
    backdrop-filter: blur(5px) saturate(200%);
    -webkit-backdrop-filter: blur(20px) saturate(200%);
    border: var(--message-border);
    border-radius: var(--message-radius);
    color: rgba(255, 255, 255, 0.8) !important;
    box-shadow: 0 4px 24px rgba(0, 0, 0, 0.25);
}

.mes {
    flex-direction: column;
    align-items: center;
    border: none !important;
    background-color: var(--ui-color-main) !important;
    margin: 0;
}

.mes_text {
    padding: 10px;
}

.mes .avatar {
    position: relative;
}

.mes_reasoning_actions.flex-container,
.mes_buttons,
.flex-container.swipeRightBlock.flexFlow {
    width: 100%;
    transform: translateX(-12px);
}

/* 头像样式 */
.avatar img {
    border: none !important;
}

/* 正则标签 */
.regex-script-label {
    max-width: 90%;
}

/* 滚动容器设置 */
#HotSwapWrapper {
    overflow-x: auto;
}
#HotSwapWrapper > * {
    flex-shrink: 0;
}

#global_scripts_block {
    max-height: 400px;
    overflow-y: auto;
    padding-right: 40px;
}

#scoped_scripts_block {
    max-height: 300px;
    overflow-y: auto;
    padding-right: 40px;
}

#user_avatar_block {
    max-height: 300px;
    overflow-y: auto;
    overflow-x: hidden;
}

/* 滚动条样式 */
#chat::-webkit-scrollbar,
[class="scrollableInner"]::-webkit-scrollbar,
#world_editor_select::-webkit-scrollbar,
#HotSwapWrapper::-webkit-scrollbar,
#scoped_scripts_block::-webkit-scrollbar {
    width: 8px;
    height: 8px;
}

/* 滚动条滑块 */
#chat::-webkit-scrollbar-thumb,
[class="scrollableInner"]::-webkit-scrollbar-thumb,
#HotSwapWrapper::-webkit-scrollbar-thumb,
#global_scripts_block::-webkit-scrollbar-thumb,
#scoped_scripts_block::-webkit-scrollbar-thumb {
    background: linear-gradient(
        45deg,
        rgba(255, 255, 255, 0.6),
        rgba(160, 180, 220, 0.5)
    );
    border-radius: 4px;
    border: 1px solid rgba(203, 240, 255, 0.4);
    box-shadow: inset 0 0 4px rgba(160, 180, 220, 0.4);
    transition: all 0.3s ease;
}

/* 特殊滚动条样式 */
#world_editor_select::-webkit-scrollbar-thumb {
    background-color: #2f90b9;
    border-radius: 10px;
    border: 2px solid transparent;
    background-clip: content-box;
    transition: all 0.3s ease;
}

#world_editor_select::-webkit-scrollbar-track {
    background: #f1f1f1;
    border-radius: 10px;
}

/* 滚动条悬停效果 */
#chat::-webkit-scrollbar-thumb:hover,
[class="scrollableInner"]::-webkit-scrollbar-thumb:hover,
#global_scripts_block::-webkit-scrollbar-thumb:hover,
#HotSwapWrapper::-webkit-scrollbar-thumb:horizontal:hover,
#scoped_scripts_block::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(
        135deg,
        rgba(255, 255, 255, 0.6),
        rgba(160, 180, 220, 0.5)
    );
    border: 1px solid rgba(200, 220, 255, 0.5);
    transform: scale(1.1);
    box-shadow: 0 0 6px rgba(200, 220, 255, 0.6);
}

/* 抽屉标题样式 */
.inline-drawer-header,
#extensions_settings .inline-drawer-toggle.inline-drawer-header, 
#extensions_settings2 .inline-drawer-toggle.inline-drawer-header,
#top-settings-holder h4:not(#ai-config-button):not(#rightNavHolder),
.standoutHeader:not(h4) {
    background: var(--bg-color) !important;
    backdrop-filter: var(--bg-effect);
    -webkit-backdrop-filter: var(--bg-effect);
    border: var(--border-style);
    border-radius: var(--border-radius);
    color: #ffffff !important;
    white-space: normal !important;
    word-wrap: break-word !important;
    overflow: hidden !important;
    text-overflow: ellipsis;
    padding: 6px 10px;
}

/* 发送表单 */
#send_form {
    background: rgba(25, 40, 65, 0.6);
    backdrop-filter: blur(2px) saturate(180%);
    -webkit-backdrop-filter: blur(15px) saturate(180%);
    border: 1px solid rgba(100, 150, 255, 0.2);
    border-radius: 16px;
    padding: 12px 16px;
    color: #E0F0FF;
    box-shadow: 0 4px 20px rgba(0, 30, 60, 0.3);
}

#send_form textarea {
    clip-path: none !important;
}

/* 底栏QR按键隐藏*/
#send_form:hover 
#qr--bar {    
  height: 65px;    
  transition: all 0.5s ease;
}
#qr--bar {    
  height: 0.1px;
}
